import json
from src.score import aggregate

# Sovereignty and trust assessment
sensor = {
    "id": "sovereignty_trust",
    "signals": [
        {"name": "autonomy_preserved", "weight": 0.4, "_value": 0.0},
        {"name": "consent_verified", "weight": 0.3, "_value": 0.0},
        {"name": "power_balance", "weight": 0.3, "_value": 0.0}
    ],
    "scoring": {"aggregation": "weighted_mean"},
    "thresholds": {"concern": 0.20, "notice": 0.40, "healthy": 0.70}
}

for sig in sensor["signals"]:
    sig["_value"] = 0.85  # example: healthy sovereignty

score = aggregate("weighted_mean", sensor["signals"])
print(f"Sovereignty score: {score:.3f}")
print(f"Band: {'healthy' if score >= 0.70 else 'notice' if score >= 0.40 else 'concern'}")
